if (data.nested && data.nested.array) {
  env.set('arrayLength', data.nested.array.length.toString());
  console.log('Array length saved:', data.nested.array.length);
}

const users = response.json();
if (users.data && users.data.length > 0) {
  // Save first user's ID for use in subsequent requests
  env.set('firstUserId', users.data[0].id.toString());
  console.log('First user ID saved:', users.data[0].id);
  console.log('Total users:', users.pagination.total);
}

items.gqlQuery:
query GetUsers {
  users {
    id
    name
    email
    role
  }
}

query GetUser($id: ID!) {
  user(id: $id) {
    id
    name
    email
    role
    posts {
      id
      title
      content
      tags
    }
  }
}

query GetPosts {
  posts {
    id
    title
    content
    tags
    user {
      id
      name
    }
    comments {
      id
      text
      user {
        name
      }
    }
  }
}

query Search($term: String!) {
  search(term: $term) {
    users {
      id
      name
      email
    }
    posts {
      id
      title
      content
    }
  }
}

mutation CreateUser($name: String!, $email: String!, $role: String) {
  createUser(name: $name, email: $email, role: $role) {
    id
    name
    email
    role
  }
}

mutation CreatePost($userId: ID!, $title: String!, $content: String!, $tags: [String!]) {
  createPost(userId: $userId, title: $title, content: $content, tags: $tags) {
    id
    title
    content
    tags
    user {
      name
    }
  }
}
